

const CFG = {
  RPC_HTTP  : 'https://mainnet.helius-rpc.com/?api-key=dd9c29d0-27a6-4611-bbf7-aec8bfa1999a',
  RPC_WS    : 'wss://mainnet.helius-rpc.com/?api-key=dd9c29d0-27a6-4611-bbf7-aec8bfa1999a',
  JUP_QUOTE : 'https://quote-api.jup.ag/v6/quote',
  JUP_SWAP  : 'https://quote-api.jup.ag/v6/swap',
  JUP_PRICE : 'https://api.jup.ag/price/v2',
  JUP_TOKEN : 'https://tokens.jup.ag/token/',
  SOL_MINT  : 'So11111111111111111111111111111111111111112',
  FEE_ACCT  : '',    // Fill in after registering at https://referral.jup.ag
  FEE_BPS   : 50,    // 0.5% platform fee
  ORIGINS   : [],    // Empty = allow all origins (dev). Set for production.
};

function cors(origin) {
  let ao = '*';
  if (CFG.ORIGINS.length && origin) {
    const ok = CFG.ORIGINS.includes(origin)
      || origin.startsWith('http://localhost')
      || origin.startsWith('http://127.0.0.1');
    ao = ok ? origin : CFG.ORIGINS[0];
  }
  return {
    'Access-Control-Allow-Origin' : ao,
    'Access-Control-Allow-Methods': 'GET,POST,OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type,Authorization',
    'Vary': 'Origin',
  };
}

const jR = (data, status = 200, origin = null) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', ...cors(origin) },
  });

async function safeJson(r) {
  try { return await r.json(); }
  catch (_) { throw new Error('Non-JSON response from upstream'); }
}

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }


// HTML is base64-encoded in chunks to avoid esbuild string-length issues
const _HTML_B64 = "";
function _decodeHTML() {
  const b64 = _HTML_B64;
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return new TextDecoder().decode(bytes);
}
const _HTML = _decodeHTML();



export default {
  async fetch(req, env, ctx) {
    const url    = new URL(req.url);
    const path   = url.pathname;
    const origin = req.headers.get('Origin') || null;

    if (req.method === 'OPTIONS')
      return new Response(null, { status: 204, headers: cors(origin) });

    // WebSocket upgrade — pass ctx so ctx.waitUntil is available inside the handler
    if (path === '/ws') return handleWS(req, env, ctx);

    try {
      // Serve embedded HTML frontend
      if (path === '/' || path === '') {
        return new Response(_HTML, {
          headers: { 'Content-Type': 'text/html;charset=utf-8' },
        });
      }

      if (path === '/health')         return jR({ ok: true, v: '3.0' },           200, origin);
      if (path === '/sol-price')      return apiSolPrice(origin);
      if (path === '/price')          return apiPrice(url, origin);
      if (path === '/quote')          return apiQuote(url, origin);
      if (path === '/swap-tx')        return apiSwapTx(req, origin);
      if (path === '/token-info')     return apiTokenInfo(url, env, origin);
      if (path === '/priority-fee')   return apiPriorityFee(origin);
      if (path === '/phantom-logo')   return apiPhantomLogo(origin);
      if (path === '/balance')        return apiBalance(url, origin, env);
      if (path === '/token-accounts') return apiTokenAccounts(url, origin, env);
      if (path === '/helius-balances') return apiHeliusBalances(url, origin, env);
      if (path === '/debug-wallet')    return apiDebugWallet(url, origin, env);

      return jR({ ok: false, error: 'Not Found' }, 404, origin);
    } catch (e) {
      return jR({ ok: false, error: e.message }, 500, origin);
    }
  },
};

/**

 */
async function handleWS(req, env, ctx) {
  if (req.headers.get('Upgrade') !== 'websocket')
    return new Response('Expected WebSocket upgrade', { status: 426 });

  const { 0: client, 1: server } = new WebSocketPair();
  server.accept();

  // Use Helius if HELIUS_KEY is available in env
  const rpcHttp  = env.HELIUS_KEY
    ? `https://mainnet.helius-rpc.com/?api-key=${env.HELIUS_KEY}`
    : CFG.RPC_HTTP;
  const rpcWsUrl = env.HELIUS_KEY
    ? `wss://mainnet.helius-rpc.com/?api-key=${env.HELIUS_KEY}`
    : CFG.RPC_WS;

  let rpcWs     = null;
  let alive     = true;
  let watchSet  = new Set();   // set of wallet addresses currently being watched
  let sigSeen   = new Set();   // deduplicate signatures
  let reconTimer = null;

  const send = obj => { try { server.send(JSON.stringify(obj)); } catch (_) {} };

  // Parse getTransaction, find tokens whose balance changed
  async function parseTx(sig, attempt = 0) {
    try {
      const r = await fetch(rpcHttp, {
        method : 'POST',
        headers: { 'Content-Type': 'application/json' },
        body   : JSON.stringify({
          jsonrpc: '2.0', id: 1,
          method : 'getTransaction',
          params : [sig, { encoding: 'jsonParsed', maxSupportedTransactionVersion: 0 }],
        }),
        signal: AbortSignal.timeout(8000),
      });
      if (!r.ok) throw new Error(`RPC HTTP ${r.status}`);
      const d = await r.json();

      // Transaction not yet processed by validator — retry up to 5x
      if (!d.result) {
        if (attempt < 5) { await sleep(2500); return parseTx(sig, attempt + 1); }
        return [];
      }

      const tx   = d.result;
      const meta = tx.meta;
      if (!meta || meta.err) return [];

      // Map preTokenBalances by accountIndex
      const preMap = {};
      (meta.preTokenBalances || []).forEach(b => {
        preMap[b.accountIndex] = {
          amt : parseFloat(b.uiTokenAmount?.uiAmount || 0),
          mint: b.mint,
        };
      });

      const accts  = tx.transaction?.message?.accountKeys || [];
      const events = [];

      for (const wallet of watchSet) {
        // Calculate SOL spent by the target wallet
        let amountInSol = 0;
        accts.forEach((acct, i) => {
          const addr = typeof acct === 'string' ? acct : acct.pubkey;
          if (addr === wallet) {
            const pre  = (meta.preBalances[i]  || 0) / 1e9;
            const post = (meta.postBalances[i] || 0) / 1e9;
            if (pre > post) amountInSol = parseFloat((pre - post).toFixed(6));
          }
        });

        for (const post of (meta.postTokenBalances || [])) {
          if (post.owner !== wallet || post.mint === CFG.SOL_MINT) continue;
          const _d=post.uiTokenAmount?.decimals??-1,_r=parseInt(post.uiTokenAmount?.amount||'0');
          if(_d===0&&_r<=1)continue;
          const pre   = preMap[post.accountIndex]?.amt || 0;
          const after = parseFloat(post.uiTokenAmount?.uiAmount || 0);

          if (after > pre + 0.000001) {
            // Token balance increased = BUY
            events.push({ wallet, mint: post.mint, action: 'buy', amountInSol, sig, decimals: _d });
          } else if (after < pre - 0.000001 && pre > 0) {
            // Token balance decreased = SELL
            const pct = Math.round(((pre - after) / pre) * 100);
            events.push({ wallet, mint: post.mint, action: 'sell', sellPct: pct, amountInSol: 0, sig, decimals: _d });
          }
        }
      }
      return events;
    } catch (_) { return []; }
  }

  // Subscribe wallet to logsSubscribe
  function subscribeWallet(wallet) {
    if (!rpcWs || rpcWs.readyState !== WebSocket.OPEN) return;
    rpcWs.send(JSON.stringify({
      jsonrpc: '2.0', id: Date.now(),
      method : 'logsSubscribe',
      params : [{ mentions: [wallet] }, { commitment: 'confirmed' }],
    }));
  }

  // Connect to Solana RPC WebSocket
  function connectRpc() {
    if (!alive) return;
    try { rpcWs = new WebSocket(rpcWsUrl); }
    catch (_) {
      send({ type: 'rpc_reconnecting' });
      reconTimer = setTimeout(connectRpc, 5000);
      return;
    }

    rpcWs.addEventListener('open', () => {
      send({ type: 'rpc_connected' });
      for (const w of watchSet) subscribeWallet(w);
    });

    rpcWs.addEventListener('message', async evt => {
      let msg;
      try { msg = JSON.parse(evt.data); } catch (_) { return; }

      // Subscription confirmation
      if (typeof msg.result === 'number' && msg.id) {
        send({ type: 'subscribed', subId: msg.result });
        return;
      }
      if (msg.method !== 'logsNotification') return;

      const val  = msg.params?.result?.value;
      if (!val) return;
      const sig  = val.signature;
      const logs = val.logs || [];

      // Dedup — skip already-processed signatures
      if (sigSeen.has(sig)) return;
      sigSeen.add(sig);
      if (sigSeen.size > 500) sigSeen.clear(); // prevent memory leak

      // Filter: only process logs that look like a swap or token transfer
      const isRelevant = logs.some(l =>
        l.includes('Program JUP') ||
        l.includes('TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA') ||
        l.includes('swap') || l.includes('Swap') ||
        l.includes('Transfer')
      );
      if (!isRelevant) return;
      const _np=['metaqbxxUerdq28cj1RbAWkYQm3ybzjb6a8bt518x1s','cndy3Z4yapfJBmL3ShUp5exZkqLc1VFhen6ZposcwaVt'];
      if(logs.some(l=>_np.some(p=>l.includes(p)))&&!logs.some(l=>l.includes('Program JUP')))return;

      // ctx is passed from the main fetch handler via closure
      ctx.waitUntil((async () => {
        const events = await parseTx(sig);
        for (const ev of events) {
          send({
            type       : 'swap_detected',
            action     : ev.action,
            wallet     : ev.wallet,
            tokenMint  : ev.mint,
            amountInSol: ev.amountInSol,
            sellPct    : ev.sellPct || 100,
            signature  : sig,
            decimals   : ev.decimals??-1,
          });
        }
      })());
    });

    rpcWs.addEventListener('close', () => {
      if (!alive) return;
      send({ type: 'rpc_reconnecting' });
      reconTimer = setTimeout(connectRpc, 4000);
    });
    rpcWs.addEventListener('error', () => {});
  }

  // Handle messages from the frontend client
  server.addEventListener('message', evt => {
    let msg;
    try { msg = JSON.parse(evt.data); } catch (_) { return; }

    if (msg.type === 'ping') {
      try { server.send(JSON.stringify({ type: 'pong' })); } catch (_) {}
      return;
    }

    if (msg.type === 'watch' && msg.wallet) {
      const isNew = !watchSet.has(msg.wallet);
      watchSet.add(msg.wallet);
      send({ type: 'watching', wallet: msg.wallet, count: watchSet.size });
      if (isNew) {
        if (!rpcWs || rpcWs.readyState > WebSocket.OPEN) {
          clearTimeout(reconTimer);
          connectRpc();
        } else {
          subscribeWallet(msg.wallet);
        }
      }
    }

    // Unwatch per-wallet — only close RPC if no wallets remain
    if (msg.type === 'unwatch' && msg.wallet) {
      watchSet.delete(msg.wallet);
      send({ type: 'unwatched', wallet: msg.wallet, count: watchSet.size });
      if (watchSet.size === 0 && rpcWs) {
        try { rpcWs.close(); } catch (_) {}
      }
    }

    if (msg.type === 'unwatch_all') {
      watchSet.clear();
      if (rpcWs) { try { rpcWs.close(); } catch (_) {} }
      send({ type: 'unwatched_all' });
    }
  });

  server.addEventListener('close', () => {
    alive = false;
    clearTimeout(reconTimer);
    try { if (rpcWs) rpcWs.close(); } catch (_) {}
  });

  return new Response(null, { status: 101, webSocket: client });
}

async function apiSolPrice(orig) {
  // Fallback chain: Binance (faster) → CoinGecko
  try {
    const r = await fetch(
      'https://api.binance.com/api/v3/ticker/price?symbol=SOLUSDT',
      { signal: AbortSignal.timeout(4000) }
    );
    if (r.ok) {
      const d = await r.json();
      return jR({ ok: true, price: parseFloat(d.price) }, 200, orig);
    }
  } catch (_) {}
  try {
    const r = await fetch(
      'https://api.coingecko.com/api/v3/simple/price?ids=solana&vs_currencies=usd',
      { signal: AbortSignal.timeout(6000) }
    );
    if (r.ok) {
      const d = await r.json();
      return jR({ ok: true, price: d.solana.usd }, 200, orig);
    }
  } catch (_) {}
  return jR({ ok: false, price: 0 }, 200, orig);
}

async function apiPrice(url, orig) {
  const mints = url.searchParams.get('mints');
  if (!mints) return jR({ ok: false, error: 'mints required' }, 400, orig);
  try {
    const r = await fetch(`${CFG.JUP_PRICE}?ids=${mints}`, { signal: AbortSignal.timeout(8000) });
    if (!r.ok) throw new Error(`JUP Price ${r.status}`);
    const d = await safeJson(r);
    return jR({ ok: true, data: d.data }, 200, orig);
  } catch (e) { return jR({ ok: false, error: e.message }, 500, orig); }
}

async function apiQuote(url, orig) {
  // Forward all params including slippageBps, platformFeeBps, feeAccount
  const params = new URLSearchParams(url.search);
  try {
    const r = await fetch(`${CFG.JUP_QUOTE}?${params}`, { signal: AbortSignal.timeout(10000) });
    if (!r.ok) throw new Error(`Jupiter Quote ${r.status}`);
    const d = await safeJson(r);
    return jR({ ok: true, quote: d }, 200, orig);
  } catch (e) { return jR({ ok: false, error: e.message }, 500, orig); }
}

async function apiSwapTx(req, orig) {
  let body;
  try { body = await req.json(); }
  catch (_) { return jR({ ok: false, error: 'Invalid JSON body' }, 400, orig); }
  try {
    const r = await fetch(CFG.JUP_SWAP, {
      method : 'POST',
      headers: { 'Content-Type': 'application/json' },
      body   : JSON.stringify(body),
      signal : AbortSignal.timeout(12000),
    });
    if (!r.ok) throw new Error(`Jupiter Swap ${r.status}`);
    const d = await safeJson(r);
    return jR({ ok: true, ...d }, 200, orig);
  } catch (e) { return jR({ ok: false, error: e.message }, 500, orig); }
}

async function apiTokenInfo(url, env, orig) {
  const mint = url.searchParams.get('mint');
  if (!mint) return jR({ ok: false, error: 'mint required' }, 400, orig);

  // Check KV cache first
  if (env.TOKEN_CACHE) {
    try {
      const cached = await env.TOKEN_CACHE.get(mint, 'json');
      if (cached) return jR({ ok: true, ...cached }, 200, orig);
    } catch (_) {}
  }

  try {
    const r = await fetch(`${CFG.JUP_TOKEN}${mint}`, { signal: AbortSignal.timeout(6000) });
    if (!r.ok) throw new Error(`Token API ${r.status}`);
    const d    = await safeJson(r);
    const _t=(d.tags||[]).map(t=>String(t).toLowerCase()),_dc=d.decimals??6,_in=_dc===0&&(_t.some(t=>['nft','compressed-nft','programmable-nft'].includes(t))||(d.supply&&parseInt(d.supply)===1));
    const info={symbol:d.symbol||mint.slice(0,6),decimals:_dc,mint,logoURI:d.logoURI||null,isNFT:_in};
    // Store in KV with 24h TTL
    if (env.TOKEN_CACHE) {
      try { await env.TOKEN_CACHE.put(mint, JSON.stringify(info), { expirationTtl: 86400 }); }
      catch (_) {}
    }
    return jR({ ok: true, ...info }, 200, orig);
  } catch (_) {
    return jR({ ok: false, symbol: mint.slice(0, 6), decimals: 6, mint, logoURI: null }, 200, orig);
  }
}


// ══ /balance?addr=... ══
async function apiBalance(url, orig, env) {
  const addr = url.searchParams.get('addr');
  if (!addr) return jR({ ok: false, error: 'addr required' }, 400, orig);
  // Use Helius first (fastest, no rate limit), then fallback to public RPCs
  const rpcs = [
    CFG.RPC_HTTP,  // Helius (primary)
    ...(env && env.HELIUS_KEY && env.HELIUS_KEY !== 'dd9c29d0-27a6-4611-bbf7-aec8bfa1999a' ? [`https://mainnet.helius-rpc.com/?api-key/${env.HELIUS_KEY}`] : []),
    'https://rpc.ankr.com/solana',
    'https://api.mainnet-beta.solana.com',
  ];
  for (const rpc of rpcs) {
    try {
      const r = await fetch(rpc, {
        method : 'POST',
        headers: { 'Content-Type': 'application/json' },
        body   : JSON.stringify({ jsonrpc: '2.0', id: 1, method: 'getBalance', params: [addr] }),
        signal : AbortSignal.timeout(8000),
      });
      if (!r.ok) continue;
      const d = await safeJson(r);
      if (d.result && typeof d.result.value === 'number') {
        return jR({ ok: true, sol: d.result.value / 1e9 }, 200, orig);
      }
    } catch (_) {}
  }
  return jR({ ok: false, error: 'Balance fetch failed', sol: 0 }, 200, orig);
}

// ══ /token-accounts?addr=... ══
// Returns all SPL token accounts for a wallet with non-zero balance
async function apiTokenAccounts(url, orig, env) {
  const addr = url.searchParams.get('addr');
  if (!addr) return jR({ ok: false, error: 'addr required' }, 400, orig);
  const key  = (env && env.HELIUS_KEY) ? env.HELIUS_KEY : 'dd9c29d0-27a6-4611-bbf7-aec8bfa1999a';
  const rpcUrl = `https://mainnet.helius-rpc.com/?api-key=${key}`;
  const rpcFallbacks = [rpcUrl, 'https://rpc.ankr.com/solana', CFG.RPC_HTTP];
  const TOKEN_PROGRAMS = [
    'TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA',
    'TokenzQdBNbequQ2hnBjuhvKnxP6hWzNe6ANGdBGY',
  ];

  for (const rpc of rpcFallbacks) {
    try {
      const [splD, t22D] = await Promise.all([
        fetch(rpc, { method:'POST', headers:{'Content-Type':'application/json'},
          body: JSON.stringify({ jsonrpc:'2.0', id:1, method:'getTokenAccountsByOwner',
            params:[addr, { programId: TOKEN_PROGRAMS[0] }, { encoding:'jsonParsed' }] }),
          signal: AbortSignal.timeout(8000) }).then(r=>r.json()),
        fetch(rpc, { method:'POST', headers:{'Content-Type':'application/json'},
          body: JSON.stringify({ jsonrpc:'2.0', id:2, method:'getTokenAccountsByOwner',
            params:[addr, { programId: TOKEN_PROGRAMS[1] }, { encoding:'jsonParsed' }] }),
          signal: AbortSignal.timeout(8000) }).then(r=>r.json()).catch(()=>({})),
      ]);
      const allAccts = [
        ...(splD.result && splD.result.value ? splD.result.value : []),
        ...(t22D.result && t22D.result.value ? t22D.result.value : []),
      ];
      if (!allAccts.length && splD.error) throw new Error(splD.error.message || 'RPC error');
      const tokens = [];
      const seen   = new Set();
      for (const acct of allAccts) {
        const info = acct && acct.account && acct.account.data
          && acct.account.data.parsed && acct.account.data.parsed.info;
        if (!info || !info.mint || seen.has(info.mint)) continue;
        seen.add(info.mint);
        const ta      = info.tokenAmount || {};
        const rawAmt  = parseInt(ta.amount || '0');
        if (rawAmt === 0) continue;
        const decimals = (ta.decimals != null) ? ta.decimals : 6;
        const balance  = (ta.uiAmount != null) ? parseFloat(ta.uiAmount) : rawAmt / Math.pow(10, decimals);
        if (!isFinite(balance) || balance <= 0) continue;
        tokens.push({ mint: info.mint, balance, decimals, rawAmount: rawAmt });
      }
      tokens.sort((a, b) => b.rawAmount - a.rawAmount);
      return jR({ ok: true, tokens }, 200, orig);
    } catch (_) {}
  }
  return jR({ ok: false, error: 'All RPCs failed', tokens: [] }, 200, orig);
}

// ══ /helius-balances?addr=... ══
// Uses Helius REST API - single call returns SOL + all SPL tokens + metadata + prices
async function apiHeliusBalances(url, orig, env) {
  const addr = url.searchParams.get('addr');
  if (!addr) return jR({ ok: false, error: 'addr required' }, 400, orig);
  const key = (env && env.HELIUS_KEY) ? env.HELIUS_KEY : 'dd9c29d0-27a6-4611-bbf7-aec8bfa1999a';
  const TOKEN_PROGRAMS = [
    'TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA',
    'TokenzQdBNbequQ2hnBjuhvKnxP6hWzNe6ANGdBGY',
  ];
  const RPCS = [
    'https://api.mainnet-beta.solana.com',
    'https://rpc.ankr.com/solana',
    `https://mainnet.helius-rpc.com/?api-key=${key}`,
    'https://solana-mainnet.rpc.extrnode.com',
  ];
  async function fetchProgram(rpcUrl, programId) {
    const res = await fetch(rpcUrl, {
      method: 'POST', headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ jsonrpc: '2.0', id: 1,
        method: 'getTokenAccountsByOwner',
        params: [addr, { programId }, { encoding: 'jsonParsed', commitment: 'confirmed' }] }),
      signal: AbortSignal.timeout(8000),
    });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const d = await res.json();
    if (d.error) throw new Error(d.error.message || JSON.stringify(d.error));
    return d.result && d.result.value ? d.result.value : [];
  }
  function parseAccounts(accts) {
    const tokens = [], seen = new Set();
    for (const acct of accts) {
      const info = acct && acct.account && acct.account.data
        && acct.account.data.parsed && acct.account.data.parsed.info;
      if (!info || !info.mint || seen.has(info.mint)) continue;
      seen.add(info.mint);
      const ta = info.tokenAmount || {};
      const rawAmt = parseInt(ta.amount || '0');
      if (rawAmt === 0) continue;
      const decimals = ta.decimals != null ? ta.decimals : 6;
      const balance = ta.uiAmount != null ? parseFloat(ta.uiAmount) : rawAmt / Math.pow(10, decimals);
      if (!isFinite(balance) || balance <= 0) continue;
      tokens.push({ mint: info.mint, balance, decimals, rawAmount: rawAmt,
        symbol: info.mint.slice(0, 6), price: 0, usdValue: 0 });
    }
    return tokens;
  }
  let sol = 0, bestTokens = [], usedRpc = 'none';
  const rpcResults = [];
  // Get SOL balance
  for (const rpcUrl of RPCS) {
    try {
      const rb = await fetch(rpcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({ jsonrpc: '2.0', id: 1, method: 'getBalance', params: [addr] }),
        signal: AbortSignal.timeout(5000) });
      const db = await rb.json();
      sol = (db.result && db.result.value ? db.result.value : 0) / 1e9;
      break;
    } catch(_) {}
  }
  // Try ALL RPCs for token accounts
  for (const rpcUrl of RPCS) {
    try {
      const [splA, t22A] = await Promise.all([
        fetchProgram(rpcUrl, TOKEN_PROGRAMS[0]).catch(() => []),
        fetchProgram(rpcUrl, TOKEN_PROGRAMS[1]).catch(() => []),
      ]);
      const tokens = parseAccounts(splA.concat(t22A));
      rpcResults.push({ rpc: rpcUrl.replace('https://','').slice(0,28), count: tokens.length, accts: splA.length + t22A.length });
      if (tokens.length > 0 && bestTokens.length === 0) {
        bestTokens = tokens;
        usedRpc = rpcUrl.replace('https://','').slice(0,20);
      }
    } catch(e) {
      rpcResults.push({ rpc: rpcUrl.replace('https://','').slice(0,28), error: e.message.slice(0,40) });
    }
  }
  // DAS API last resort
  if (bestTokens.length === 0) {
    try {
      const dr = await fetch(`https://mainnet.helius-rpc.com/?api-key=${key}`, {
        method: 'POST', headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({ jsonrpc: '2.0', id: 1, method: 'getAssetsByOwner',
          params: { ownerAddress: addr, page: 1, limit: 1000,
            displayOptions: { showFungible: true, showNativeBalance: true } } }),
        signal: AbortSignal.timeout(10000),
      });
      const dd = await dr.json();
      if (!dd.error && dd.result && dd.result.items) {
        for (const item of dd.result.items) {
          if (item.interface !== 'FungibleToken' && item.interface !== 'FungibleAsset') continue;
          const ti = item.token_info || {};
          const rawAmt = ti.balance || 0;
          if (rawAmt <= 0) continue;
          const decimals = ti.decimals || 0;
          const balance = decimals > 0 ? rawAmt / Math.pow(10, decimals) : rawAmt;
          if (balance <= 0) continue;
          const meta = (item.content && item.content.metadata) || {};
          // Extract supply and dev wallet from DAS
          const supply = ti.supply != null ? ti.supply : 0;
          const supplyUi = supply > 0 && decimals > 0 ? supply / Math.pow(10, decimals) : supply;
          const authorities = item.authorities || [];
          const mintAuth = authorities.find(a => a.scopes && a.scopes.includes('mint'));
          const devWallet = mintAuth ? mintAuth.address : null;
          const pricePerToken = ti.price_info ? (ti.price_info.price_per_token || 0) : 0;
          // Extract logoURI from DAS content.links.image or content.files[0].uri
          const links = (item.content && item.content.links) || {};
          const files = (item.content && item.content.files) || [];
          const logoURI = links.image || (files[0] && files[0].uri) || null;
          bestTokens.push({ mint: item.id, balance, decimals, rawAmount: rawAmt,
            symbol: meta.symbol || meta.name || item.id.slice(0, 6),
            name: meta.name || '',
            price: pricePerToken,
            usdValue: balance * pricePerToken,
            supply: supply,
            supplyUi: supplyUi,
            devWallet: devWallet,
            logoURI: logoURI,
            priceChange24h: null,
          });
        }
        if (bestTokens.length > 0) usedRpc = 'DAS';
      }
      rpcResults.push({ rpc: 'DAS', count: bestTokens.length,
        dasItems: dd.result ? dd.result.items.length : 0, dasError: dd.error || null });
    } catch(e) {
      rpcResults.push({ rpc: 'DAS', error: e.message.slice(0,40) });
    }
  }

  // ── Price enrichment cascade ──
  if (bestTokens.length > 0) {
    const nonSolTokens = bestTokens.filter(function(t){ return t.mint !== 'So11111111111111111111111111111111111111112'; });
    const mintList = nonSolTokens.map(function(t){ return t.mint; }).join(',');
    const priceLog = [];

    // 1. GeckoTerminal multi — free, no key, covers meme coins, has 24h change
    if (mintList) {
      try {
        const gtr = await fetch(
          'https://api.geckoterminal.com/api/v2/networks/solana/tokens/multi/' + mintList,
          { headers: { 'Accept': 'application/json;version=20230302' }, signal: AbortSignal.timeout(10000) }
        );
        if (gtr.ok) {
          const gtd = await gtr.json();
          const gtMap = {};
          for (const item of (gtd.data || [])) {
            if (item.attributes && item.attributes.address) {
              gtMap[item.attributes.address] = item.attributes;
            }
          }
          for (const t of bestTokens) {
            const a = gtMap[t.mint];
            if (a && a.price_usd && parseFloat(a.price_usd) > 0) {
              t.price = parseFloat(a.price_usd);
              t.usdValue = t.balance * t.price;
              if (a.price_change_percentage && a.price_change_percentage.h24 != null) {
                t.priceChange24h = parseFloat(a.price_change_percentage.h24);
              }
              priceLog.push(t.symbol + ':GT:$' + t.price.toFixed(8));
            }
          }
        } else {
          priceLog.push('GT_ERR:' + gtr.status);
        }
      } catch(e) { priceLog.push('GT_EX:' + e.message.slice(0,20)); }
    }

    // 2. Jupiter Price v2 — fallback for tokens GeckoTerminal missed
    const stillUnpriced = bestTokens.filter(function(t){ return !t.price || t.price <= 0; });
    if (stillUnpriced.length > 0) {
      try {
        const jupMints = stillUnpriced.map(function(t){ return t.mint; }).join(',');
        const jr = await fetch('https://api.jup.ag/price/v2?ids=' + jupMints, { signal: AbortSignal.timeout(6000) });
        if (jr.ok) {
          const jd = await jr.json();
          if (jd.data) {
            for (const t of bestTokens) {
              if (t.price > 0) continue;
              const pd = jd.data[t.mint];
              if (pd && pd.price) {
                t.price = parseFloat(pd.price); t.usdValue = t.balance * t.price;
                priceLog.push(t.symbol + ':JUP:$' + t.price.toFixed(8));
              }
            }
          }
        } else { priceLog.push('JUP_ERR:' + jr.status); }
      } catch(e) { priceLog.push('JUP_EX:' + e.message.slice(0,20)); }
    }

    // 3. GeckoTerminal pools — 24h change from highest-liquidity pool
    const need24h = bestTokens.filter(function(t){ return t.price > 0 && t.priceChange24h == null; });
    for (const t of need24h) {
      try {
        const pr = await fetch(
          'https://api.geckoterminal.com/api/v2/networks/solana/tokens/' + t.mint + '/pools?page=1',
          { headers: { 'Accept': 'application/json;version=20230302' }, signal: AbortSignal.timeout(6000) }
        );
        if (pr.ok) {
          const pd = await pr.json();
          const pools = (pd.data || []);
          // Sort by reserve_in_usd descending (highest liquidity first)
          pools.sort(function(a, b) {
            const ra = parseFloat((a.attributes && a.attributes.reserve_in_usd) || 0);
            const rb = parseFloat((b.attributes && b.attributes.reserve_in_usd) || 0);
            return rb - ra;
          });
          for (const pool of pools) {
            const pa = pool.attributes || {};
            const pcp = pa.price_change_percentage || {};
            if (pcp.h24 != null) {
              t.priceChange24h = parseFloat(pcp.h24);
              // Also update price from pool if more accurate
              if (pa.base_token_price_usd && parseFloat(pa.base_token_price_usd) > 0) {
                const poolPrice = parseFloat(pa.base_token_price_usd);
                // Use pool price if close to current price (within 20%)
                if (!t.price || Math.abs(poolPrice - t.price) / t.price < 0.2) {
                  t.price = poolPrice;
                  t.usdValue = t.balance * t.price;
                }
              }
              priceLog.push(t.symbol + ':24h:' + t.priceChange24h.toFixed(2) + '%');
              break;
            }
          }
        } else {
          priceLog.push(t.symbol + ':pools_err:' + pr.status);
        }
      } catch(e) { priceLog.push(t.symbol + ':pools_ex:' + e.message.slice(0,15)); }
    }

    if (priceLog.length > 0) console.log('[PRICE]', priceLog.join(', '));
  }

  bestTokens.sort(function(a,b){ return b.rawAmount - a.rawAmount; });
  const priceDebug = bestTokens.map(function(t){ return t.symbol+':'+t.price.toFixed(8)+'('+(t.priceChange24h!=null?t.priceChange24h.toFixed(2)+'%':'?')+')'; });
  return jR({ ok: true, sol, solPrice: 0, tokens: bestTokens,
    debug: { tokenCount: bestTokens.length, source: usedRpc, rpcResults, prices: priceDebug } },
    200, orig);
}

async function apiDebugWallet(url, orig, env) {
  const addr = url.searchParams.get('addr');
  if (!addr) return jR({ error: 'addr required' }, 400, orig);
  const key = (env && env.HELIUS_KEY) ? env.HELIUS_KEY : 'dd9c29d0-27a6-4611-bbf7-aec8bfa1999a';
  const rpcUrl = `https://mainnet.helius-rpc.com/?api-key=${key}`;
  const TOKEN_PROGRAMS = [
    'TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA',
    'TokenzQdBNbequQ2hnBjuhvKnxP6hWzNe6ANGdBGY',
  ];
  const results = {};
  try {
    for (const prog of TOKEN_PROGRAMS) {
      const r = await fetch(rpcUrl, { method:'POST', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({ jsonrpc:'2.0', id:1, method:'getTokenAccountsByOwner',
          params:[addr, { programId: prog }, { encoding:'jsonParsed' }] }),
        signal: AbortSignal.timeout(10000) });
      const d = await r.json();
      const label = prog.slice(0,6);
      results[label] = {
        count : d.result && d.result.value ? d.result.value.length : 0,
        error : d.error ? (d.error.message || JSON.stringify(d.error)) : null,
        mints : d.result && d.result.value
          ? d.result.value.slice(0,3).map(a => {
              const info = a.account && a.account.data && a.account.data.parsed && a.account.data.parsed.info;
              return info ? info.mint.slice(0,12) : '?';
            })
          : [],
      };
    }
    // Also try Helius REST API
    try {
      const hr = await fetch(`https://api.helius.xyz/v0/addresses/${addr}/balances?api-key=${key}`,
        { signal: AbortSignal.timeout(8000) });
      const hd = await hr.json();
      results.helius_rest = {
        tokenCount : hd.tokens ? hd.tokens.length : 0,
        nativeSol  : hd.nativeBalance ? hd.nativeBalance.lamports / 1e9 : 0,
        error      : hd.error || null,
      };
    } catch(e) { results.helius_rest = { error: e.message }; }
    return jR({ addr: addr.slice(0,8) + '...' + addr.slice(-4), addrLen: addr.length,
      keyPrefix: key.slice(0,8), results }, 200, orig);
  } catch(e) { return jR({ error: e.message, addr: addr.slice(0,8) }, 200, orig); }
}

async function apiPhantomLogo(orig) {
  const url = 'https://raw.githubusercontent.com/anza-xyz/wallet-adapter/master/packages/wallets/phantom/src/phantom.png';
  try {
    const r = await fetch(url, { signal: AbortSignal.timeout(8000) });
    if (r.ok) {
      const buf = await r.arrayBuffer();
      return new Response(buf, { status: 200, headers: {
        'Content-Type': 'image/png',
        'Cache-Control': 'public, max-age=604800, immutable',
        'Access-Control-Allow-Origin': '*',
      }});
    }
  } catch (_) {}
  return new Response(null, { status: 404 });
}

async function apiPriorityFee(orig) {
  try {
    const r = await fetch(CFG.RPC_HTTP, {
      method : 'POST',
      headers: { 'Content-Type': 'application/json' },
      body   : JSON.stringify({
        jsonrpc: '2.0', id: 1,
        method : 'getRecentPrioritizationFees',
        params : [],
      }),
      signal: AbortSignal.timeout(6000),
    });
    if (!r.ok) throw new Error(`RPC ${r.status}`);
    const d    = await safeJson(r);
    const fees = (d.result || [])
      .map(f => f.prioritizationFee)
      .filter(f => f > 0)
      .sort((a, b) => a - b);
    const p50  = fees.length ? fees[Math.floor(fees.length * 0.50)] : 1000;
    const p85  = fees.length ? fees[Math.floor(fees.length * 0.85)] : 5000;
    const p95  = fees.length ? fees[Math.floor(fees.length * 0.95)] : 20000;
    return jR({ ok: true, slow: Math.max(p50, 1000), fast: Math.max(p85, 5000), turbo: Math.max(p95, 20000) }, 200, orig);
  } catch (_) {
    return jR({ ok: true, slow: 1000, fast: 5000, turbo: 20000 }, 200, orig);
  }
}
